 package FullDesign  {

	// Imports
	private import ScalarValues::*;
	private import Time::*;

	// Functions
	action def rand  {
		in delayMin : Integer;
		in delayMax : Integer;
		out randomValue : Integer;
	}

	// Definition of signal types
	item def __type_Wallet_getCoin {
		attribute nbOfCoins : Integer;
	}
	item def __type_Wallet_putCoin {
		attribute nbOfCoins : Integer;
	}
	item def __type_CoffeeMachine_pushCoffeeButton;
	item def __type_CoffeeMachine_pushTeaButton;
	item def __type_CoffeeMachine_getCoin {
		attribute nbOfCoins : Integer;
	}
	item def __type_CoffeeMachine_ejectCoin {
		attribute nbOfCoins : Integer;
	}
	item def __type_CoffeeMachine_pushCappuccinoButton;
	item def __type_CoffeeMachine_beverageCollected;
	item def __type_TeaButton_push;
	item def __type_CoffeeButton_push;
	item def __type_CappuccinoButton_push;

	// Definition of parts
	part def Block__Wallet {
		attribute nbOfCoins : Integer = 2;
		attribute x : Integer = 1;
		attribute minUserDelay : Integer = 20;
		attribute maxUserDelay : Integer = 40;

		action def  contentOfWallet {
			in nbOfCoins : Integer;
		}

		// Signals
		in item getCoin :  __type_Wallet_getCoin;

		out item putCoin :  __type_Wallet_putCoin;


		state mainState__ {
			entry; then start__;


			state main;

			transition from_main__0 first main
			do action  {
				first start;
				then action msg accept getCoin : __type_Wallet_getCoin;
				then assign x := msg.getCoin.nbOfCoins;
				then done;
			}
			then afterReceiving__0;


			state afterReceiving__0;

			transition from_afterReceiving__0__1 first afterReceiving__0
			do action  {
				first start;
				then assign nbOfCoins := nbOfCoins+x;
				then ref action = contentOfWallet (nbOfCoins);
				then done;
			}
			then main;


			transition from_main__2 first main
			do action  {
				first start;
				then assign putCoin.nbOfCoins := x;
				then send putCoin;
				then done;
			}
			then afterSending__1;


			state afterSending__1;

			transition from_afterSending__1__3 first afterSending__1
			accept after rand(minUserDelay,maxUserDelay)[SI::s]
			do action  {
				first start;
				then assign nbOfCoins := nbOfCoins-x;
				then ref action = contentOfWallet (nbOfCoins);
				then done;
			}
			then main;


			state start__;

			transition from_start____0 first start__
			do action  {
				first start;
				then ref action = contentOfWallet (nbOfCoins);
				then assign nbOfCoins := 2;
				then done;
			}
			then main;


		}
	}

	part def Block__CoffeeMachine {
		attribute teaMinDelay : Integer = 3;
		attribute teaMaxDelay : Integer = 8;
		attribute coffeeMinDelay : Integer = 5;
		attribute coffeeMaxDelay : Integer = 10;
		attribute coinDelay : Integer = 30;
		attribute x : Integer;
		attribute nbOfCoins : Integer = 0;

		action def  beverageReady {
		}

		// Signals
		in item pushCoffeeButton :  __type_CoffeeMachine_pushCoffeeButton;

		in item pushTeaButton :  __type_CoffeeMachine_pushTeaButton;

		in item getCoin :  __type_CoffeeMachine_getCoin;

		out item ejectCoin :  __type_CoffeeMachine_ejectCoin;

		in item pushCappuccinoButton :  __type_CoffeeMachine_pushCappuccinoButton;

		in item beverageCollected :  __type_CoffeeMachine_beverageCollected;


		state mainState__ {
			entry; then start__;


			state EjectState;

			transition from_EjectState__0 first EjectState
			do action  {
				first start;
				then assign ejectCoin.nbOfCoins := nbOfCoins;
				then send ejectCoin;
				then done;
			}
			then afterSending__0;


			state afterSending__0;

			transition from_afterSending__0__1 first afterSending__0
			do action  {
				first start;
				then assign nbOfCoins := 0;
				then done;
			}
			then WaitingForFirstCoin;


			state WaitingForSecondCoin;

			transition from_WaitingForSecondCoin__0 first WaitingForSecondCoin
			do action  {
				first start;
				then action msg accept getCoin : __type_CoffeeMachine_getCoin;
				then assign x := msg.getCoin.nbOfCoins;
				then done;
			}
			then afterReceiving__1;


			state afterReceiving__1;

			transition from_afterReceiving__1__1 first afterReceiving__1
			do action  {
				first start;
				then assign nbOfCoins := 2;
				then done;
			}
			then Beverage;


			transition from_WaitingForSecondCoin__2 first WaitingForSecondCoin
			accept after coinDelay[SI::s]
			then EjectState;


			state start__;

			transition from_start____0 first start__
			then WaitingForFirstCoin;


			state WaitingForFirstCoin;

			transition from_WaitingForFirstCoin__0 first WaitingForFirstCoin
			do action  {
				first start;
				then action msg accept getCoin : __type_CoffeeMachine_getCoin;
				then assign x := msg.getCoin.nbOfCoins;
				then done;
			}
			then afterReceiving__2;


			state afterReceiving__2;

			transition from_afterReceiving__2__1 first afterReceiving__2
			do action  {
				first start;
				then assign nbOfCoins := nbOfCoins+x;
				then done;
			}
			then WaitingForSecondCoin;


			state TeaDelivered;

			state Beverage;

			transition from_Beverage__0 first Beverage
			then WaitingForSelection;


			state CoffeeDelivered;

			state WaitingForSelection;

			transition from_WaitingForSelection__0 first WaitingForSelection
			do action  {
				first start;
				then action msg accept pushCoffeeButton : __type_CoffeeMachine_pushCoffeeButton;
				then done;
			}
			then afterReceiving__3;


			state afterReceiving__3;

			transition from_afterReceiving__3__1 first afterReceiving__3
			do action  {
				first start;
				then assign nbOfCoins := 0;
				then action compute : beverageReady;
				then done;
			}
			then CoffeeDelivered;


			transition from_WaitingForSelection__2 first WaitingForSelection
			do action  {
				first start;
				then action msg accept pushTeaButton : __type_CoffeeMachine_pushTeaButton;
				then done;
			}
			then afterReceiving__4;


			state afterReceiving__4;

			transition from_afterReceiving__4__3 first afterReceiving__4
			do action  {
				first start;
				then assign nbOfCoins := 0;
				then action compute : beverageReady;
				then done;
			}
			then TeaDelivered;


			transition from_WaitingForSelection__4 first WaitingForSelection
			accept after coinDelay[SI::s]
			do action  {
				first start;
				then assign ejectCoin.nbOfCoins := nbOfCoins;
				then send ejectCoin;
				then done;
			}
			then afterSending__5;


			state afterSending__5;

			transition from_afterSending__5__5 first afterSending__5
			do action  {
				first start;
				then assign nbOfCoins := 0;
				then done;
			}
			then WaitingForFirstCoin;


		}
	}

	part def Block__TeaButton {
		attribute mechanicalDelay : Integer = 10;

		// Signals
		out item push :  __type_TeaButton_push;

		in item pushCoffeeButton :  __type_CoffeeMachine_pushCoffeeButton;

		in item pushTeaButton :  __type_CoffeeMachine_pushTeaButton;

		in item getCoin :  __type_CoffeeMachine_getCoin;

		out item ejectCoin :  __type_CoffeeMachine_ejectCoin;

		in item pushCappuccinoButton :  __type_CoffeeMachine_pushCappuccinoButton;

		in item beverageCollected :  __type_CoffeeMachine_beverageCollected;


		state mainState__ {
			entry; then start__;


			state main;

			transition from_main__0 first main
			do action  {
				first start;
				then send push;
				then done;
			}
			then afterSending__0;


			state afterSending__0;

			transition from_afterSending__0__1 first afterSending__0
			accept after mechanicalDelay[SI::s]
			then main;


			state start__;

			transition from_start____0 first start__
			then main;


		}
	}

	part def Block__CoffeeButton {
		attribute mechanicalDelay : Integer = 10;

		// Signals
		out item push :  __type_CoffeeButton_push;

		in item pushCoffeeButton :  __type_CoffeeMachine_pushCoffeeButton;

		in item pushTeaButton :  __type_CoffeeMachine_pushTeaButton;

		in item getCoin :  __type_CoffeeMachine_getCoin;

		out item ejectCoin :  __type_CoffeeMachine_ejectCoin;

		in item pushCappuccinoButton :  __type_CoffeeMachine_pushCappuccinoButton;

		in item beverageCollected :  __type_CoffeeMachine_beverageCollected;


		state mainState__ {
			entry; then start__;


			state main;

			transition from_main__0 first main
			then state0;


			state start__;

			transition from_start____0 first start__
			then main;


			state state0;

			transition from_state0__0 first state0
			do action  {
				first start;
				then send push;
				then done;
			}
			then afterSending__0;


			state afterSending__0;

			transition from_afterSending__0__1 first afterSending__0
			accept after mechanicalDelay[SI::s]
			then main;


		}
	}

	part def Block__CappuccinoButton {
		attribute mechanicalDelay : Integer = 10;

		// Signals
		out item push :  __type_CappuccinoButton_push;

		in item pushCoffeeButton :  __type_CoffeeMachine_pushCoffeeButton;

		in item pushTeaButton :  __type_CoffeeMachine_pushTeaButton;

		in item getCoin :  __type_CoffeeMachine_getCoin;

		out item ejectCoin :  __type_CoffeeMachine_ejectCoin;

		in item pushCappuccinoButton :  __type_CoffeeMachine_pushCappuccinoButton;

		in item beverageCollected :  __type_CoffeeMachine_beverageCollected;


		state mainState__ {
			entry; then start__;


			state main;

			transition from_main__0 first main
			do action  {
				first start;
				then send push;
				then done;
			}
			then afterSending__0;


			state afterSending__0;

			transition from_afterSending__0__1 first afterSending__0
			accept after mechanicalDelay[SI::s]
			then main;


			state start__;

			transition from_start____0 first start__
			then main;


		}
	}

	// Usage of parts
	part Wallet : Block__Wallet {
	}

	part CoffeeMachine : Block__CoffeeMachine {
		part TeaButton : Block__TeaButton {
		}

		part CoffeeButton : Block__CoffeeButton {
		}

		part CappuccinoButton : Block__CappuccinoButton {
		}

	}

	// Connection between signals
	enum def CommunicationKind {
		synchronous;
		asynchronous;
	}

	connect CoffeeMachine.CappuccinoButton.push to CoffeeMachine.pushCappuccinoButton  {
		communicationKind = CommunicationKind::synchronous;
		isPrivate = true;
		isLossy = false;

	}

	connect CoffeeMachine.CoffeeButton.push to CoffeeMachine.pushCoffeeButton  {
		communicationKind = CommunicationKind::synchronous;
		isPrivate = true;
		isLossy = false;

	}

	connect Wallet.getCoin to CoffeeMachine.ejectCoin  {
		communicationKind = CommunicationKind::synchronous;
		isPrivate = true;
		isLossy = false;

	}

	connect Wallet.putCoin to CoffeeMachine.getCoin  {
		communicationKind = CommunicationKind::synchronous;
		isPrivate = true;
		isLossy = false;

	}

	connect CoffeeMachine.TeaButton.push to CoffeeMachine.pushTeaButton  {
		communicationKind = CommunicationKind::synchronous;
		isPrivate = true;
		isLossy = false;

	}


}

