		in item pushCoffeeButton :  __type_CoffeeMachine_pushCoffeeButton;

		in item pushTeaButton :  __type_CoffeeMachine_pushTeaButton;

		in item getCoin :  __type_CoffeeMachine_getCoin;

		out item ejectCoin :  __type_CoffeeMachine_ejectCoin;

		in item pushCappuccinoButton :  __type_CoffeeMachine_pushCappuccinoButton;


		state mainState__ {
			entry; then start__;


			state EjectState;

			transition from_EjectState__0 first EjectState
			do action  {
				first start;
				then assign ejectCoin.nbOfCoins := nbOfCoins;
				then send ejectCoin;
				then done;
			}
			then afterSending__0;


			state afterSending__0;

			transition from_afterSending__0__1 first afterSending__0
			do action  {
				first start;
				then assign nbOfCoins := 0;
				then done;
			}
			then WaitingForFirstCoin;


			state WaitingForSecondCoin;

			transition from_WaitingForSecondCoin__0 first WaitingForSecondCoin
			do action  {
				first start;
				then action msg accept getCoin : __type_CoffeeMachine_getCoin;
				then assign x := msg.getCoin.nbOfCoins;
				then done;
			}
			then afterReceiving__1;


			state afterReceiving__1;

			transition from_afterReceiving__1__1 first afterReceiving__1
			do action  {
				first start;
				then assign nbOfCoins := 2;
				then done;
			}
			then Beverage;


			transition from_WaitingForSecondCoin__2 first WaitingForSecondCoin
			accept after coinDelay[SI::s]
			then EjectState;


			state start__;

			transition from_start____0 first start__
			then WaitingForFirstCoin;


			state WaitingForFirstCoin;

			transition from_WaitingForFirstCoin__0 first WaitingForFirstCoin
			do action  {
				first start;
				then action msg accept getCoin : __type_CoffeeMachine_getCoin;
				then assign x := msg.getCoin.nbOfCoins;
				then done;
			}
			then afterReceiving__2;


			state afterReceiving__2;

			transition from_afterReceiving__2__1 first afterReceiving__2
			do action  {
				first start;
				then assign nbOfCoins := nbOfCoins+x;
				then done;
			}
			then WaitingForSecondCoin;


			state TeaDelivered;

			transition from_TeaDelivered__0 first TeaDelivered
			then WaitingForFirstCoin;


			state Beverage;

			transition from_Beverage__0 first Beverage
			then WaitingForSelection;


			state CoffeeDelivered;

			transition from_CoffeeDelivered__0 first CoffeeDelivered
			then WaitingForFirstCoin;


			state PreparingCoffee;

			transition from_PreparingCoffee__0 first PreparingCoffee
			accept after 10[SI::s]
			do action  {
				first start;
				then action compute : beverageReady;
				then done;
			}
			then CoffeeDelivered;


			state PreparingTea;

			transition from_PreparingTea__0 first PreparingTea
			accept after 8[SI::s]
			do action  {
				first start;
				then action compute : beverageReady;
				then done;
			}
			then TeaDelivered;


			state WaitingForSelection;

			transition from_WaitingForSelection__0 first WaitingForSelection
			do action  {
				first start;
				then action msg accept pushCoffeeButton : __type_CoffeeMachine_pushCoffeeButton;
				then done;
			}
			then afterReceiving__3;


			state afterReceiving__3;

			transition from_afterReceiving__3__1 first afterReceiving__3
			do action  {
				first start;
				then assign nbOfCoins := 0;
				then done;
			}
			then PreparingCoffee;


			transition from_WaitingForSelection__2 first WaitingForSelection
			do action  {
				first start;
				then action msg accept pushTeaButton : __type_CoffeeMachine_pushTeaButton;
				then done;
			}
			then afterReceiving__4;


			state afterReceiving__4;

			transition from_afterReceiving__4__3 first afterReceiving__4
			do action  {
				first start;
				then assign nbOfCoins := 0;
				then done;
			}
			then PreparingTea;


			transition from_WaitingForSelection__4 first WaitingForSelection
			accept after coinDelay[SI::s]
			do action  {
				first start;
				then assign ejectCoin.nbOfCoins := nbOfCoins;
				then send ejectCoin;
				then done;
			}
			then afterSending__5;


			state afterSending__5;

			transition from_afterSending__5__5 first afterSending__5
			do action  {
				first start;
				then assign nbOfCoins := 0;
				then done;
			}
			then WaitingForFirstCoin;


		}
	}

	part def Block__TeaButton {
		attribute mechanicalDelay : Integer = 10;

		// Signals
		out item push :  __type_TeaButton_push;

		in item pushCoffeeButton :  __type_CoffeeMachine_pushCoffeeButton;

		in item pushTeaButton :  __type_CoffeeMachine_pushTeaButton;

		in item getCoin :  __type_CoffeeMachine_getCoin;

